import type * as DMMF from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'string',
  DateTime: 'string',
  Json: 'unknown',
  BigInt: 'bigint',
  Bytes: 'Buffer',
}

/** Maps a Prisma DMMF field type to its TypeScript equivalent. */
export function mapScalarType(type: string): string {
  return SCALAR_TYPE_MAP[type] ?? 'unknown'
}

/** Returns the full TypeScript type string for a DMMF field, accounting for lists and optionality. */
export function fieldToTsType(field: DMMF.Field): string {
  let tsType: string

  switch (field.kind) {
    case 'scalar':
      tsType = mapScalarType(field.type)
      break
    case 'enum':
      tsType = field.type
      break
    case 'object':
      tsType = field.type
      break
    default:
      tsType = 'unknown'
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }

  if (!field.isRequired && !field.isList) {
    tsType = `${tsType} | null`
  }

  return tsType
}

/**
 * Returns the TypeScript type for a field used in create input,
 * where fields with defaults or auto-generated values become optional.
 */
export function fieldToCreateInputType(field: DMMF.Field): { type: string; optional: boolean } {
  const baseType = fieldToTsType(field)
  const optional = !field.isRequired || field.hasDefaultValue || field.isGenerated === true || field.isUpdatedAt === true

  return { type: baseType, optional }
}

/**
 * Returns the TypeScript type for a field used in update input,
 * where all fields are optional.
 */
export function fieldToUpdateInputType(field: DMMF.Field): string {
  const base = fieldToTsType(field)
  return base
}

