import type * as DMMF from '@prisma/dmmf'

import { fieldToCreateInputType, fieldToTsType } from './type-mapper'

/**
 * Generates a complete TypeScript REST API client module from DMMF models and enums.
 * Produces interfaces for each model plus a client class with CRUD methods.
 */
export function generateRestClient(dmmf: DMMF.Document): string {
  const lines: string[] = []

  lines.push(header())
  lines.push('')

  for (const enumDef of dmmf.datamodel.enums) {
    lines.push(generateEnum(enumDef))
    lines.push('')
  }

  for (const model of dmmf.datamodel.models) {
    lines.push(generateModelInterface(model))
    lines.push('')
    lines.push(generateCreateInput(model))
    lines.push('')
    lines.push(generateUpdateInput(model))
    lines.push('')
  }

  lines.push(generateWhereUniqueInput(dmmf.datamodel.models))
  lines.push('')
  lines.push(generateClientClass(dmmf.datamodel.models))

  return lines.join('\n')
}

function header(): string {
  return [
    '// ======================================================',
    '// Generated by @prisma/client-generator-rest',
    '// Do not edit this file manually.',
    '// ======================================================',
    '',
    'type RequestOptions = {',
    '  headers?: Record<string, string>',
    '  signal?: AbortSignal',
    '}',
  ].join('\n')
}

function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const members = enumDef.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${enumDef.name} {\n${members}\n}`
}

function generateModelInterface(model: DMMF.Model): string {
  const fields = scalarAndEnumFields(model)
  const props = fields.map((f) => {
    const tsType = fieldToTsType(f)
    return `  ${f.name}: ${tsType}`
  })
  return `export interface ${model.name} {\n${props.join('\n')}\n}`
}

function generateCreateInput(model: DMMF.Model): string {
  const fields = scalarAndEnumFields(model)
  const props = fields.map((f) => {
    const { type, optional } = fieldToCreateInputType(f)
    const optionalMark = optional ? '?' : ''
    return `  ${f.name}${optionalMark}: ${type}`
  })
  return `export interface ${model.name}CreateInput {\n${props.join('\n')}\n}`
}

function generateUpdateInput(model: DMMF.Model): string {
  const fields = scalarAndEnumFields(model)
  const props = fields.map((f) => {
    const tsType = fieldToTsType(f)
    return `  ${f.name}?: ${tsType}`
  })
  return `export interface ${model.name}UpdateInput {\n${props.join('\n')}\n}`
}

function generateWhereUniqueInput(models: readonly DMMF.Model[]): string {
  const types: string[] = []
  for (const model of models) {
    const idFields = model.fields.filter((f) => f.isId)
    if (idFields.length === 0) continue
    const props = idFields.map((f) => `  ${f.name}: ${fieldToTsType(f)}`).join('\n')
    types.push(`export interface ${model.name}WhereUniqueInput {\n${props}\n}`)
  }
  return types.join('\n\n')
}

function generateClientClass(models: readonly DMMF.Model[]): string {
  const lines: string[] = []

  lines.push('export class RestApiClient {')
  lines.push('  #baseUrl: string')
  lines.push('  #defaultHeaders: Record<string, string>')
  lines.push('')
  lines.push('  constructor(baseUrl: string, defaultHeaders: Record<string, string> = {}) {')
  lines.push('    this.#baseUrl = baseUrl.replace(/\\/$/, \'\')')
  lines.push('    this.#defaultHeaders = {')
  lines.push("      'Content-Type': 'application/json',")
  lines.push('      ...defaultHeaders,')
  lines.push('    }')
  lines.push('  }')
  lines.push('')
  lines.push('  async #request<T>(path: string, init: RequestInit & RequestOptions = {}): Promise<T> {')
  lines.push('    const { headers: extraHeaders, signal, ...rest } = init')
  lines.push('    const response = await fetch(`${this.#baseUrl}${path}`, {')
  lines.push('      ...rest,')
  lines.push('      signal,')
  lines.push('      headers: { ...this.#defaultHeaders, ...extraHeaders },')
  lines.push('    })')
  lines.push('    if (!response.ok) {')
  lines.push("      throw new Error(`REST API error: ${response.status} ${response.statusText}`)")
  lines.push('    }')
  lines.push('    return response.json() as Promise<T>')
  lines.push('  }')

  for (const model of models) {
    const idField = model.fields.find((f) => f.isId)
    if (!idField) continue

    const name = model.name
    const resource = pluralize(camelCase(name))
    const idType = fieldToTsType(idField)

    lines.push('')
    lines.push(`  // ----- ${name} -----`)
    lines.push('')
    lines.push(
      `  /** Retrieve all ${name} records. */`,
      `  async ${resource}FindMany(options?: RequestOptions): Promise<${name}[]> {`,
      `    return this.#request<${name}[]>('/${resource}', options)`,
      '  }',
    )
    lines.push('')
    lines.push(
      `  /** Retrieve a single ${name} by its unique identifier. */`,
      `  async ${resource}FindUnique(where: ${name}WhereUniqueInput, options?: RequestOptions): Promise<${name}> {`,
      `    return this.#request<${name}>(\`/${resource}/\${where.${idField.name}}\`, options)`,
      '  }',
    )
    lines.push('')
    lines.push(
      `  /** Create a new ${name} record. */`,
      `  async ${resource}Create(data: ${name}CreateInput, options?: RequestOptions): Promise<${name}> {`,
      `    return this.#request<${name}>('/${resource}', { method: 'POST', body: JSON.stringify(data), ...options })`,
      '  }',
    )
    lines.push('')
    lines.push(
      `  /** Update an existing ${name} record. */`,
      `  async ${resource}Update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput, options?: RequestOptions): Promise<${name}> {`,
      `    return this.#request<${name}>(\`/${resource}/\${where.${idField.name}}\`, { method: 'PATCH', body: JSON.stringify(data), ...options })`,
      '  }',
    )
    lines.push('')
    lines.push(
      `  /** Delete a ${name} record. */`,
      `  async ${resource}Delete(where: ${name}WhereUniqueInput, options?: RequestOptions): Promise<${name}> {`,
      `    return this.#request<${name}>(\`/${resource}/\${where.${idField.name}}\`, { method: 'DELETE', ...options })`,
      '  }',
    )
  }

  lines.push('}')
  return lines.join('\n')
}

/** Filters model fields to only scalar and enum kinds (skips relations). */
function scalarAndEnumFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
}

function camelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

/**
 * Naive English pluralizer. Covers the most common cases found in Prisma model names
 * without pulling in a runtime dependency.
 */
function pluralize(word: string): string {
  if (word.endsWith('s') || word.endsWith('x') || word.endsWith('z') || word.endsWith('sh') || word.endsWith('ch')) {
    return word + 'es'
  }
  if (word.endsWith('y') && !isVowel(word.charAt(word.length - 2))) {
    return word.slice(0, -1) + 'ies'
  }
  return word + 's'
}

function isVowel(char: string): boolean {
  return 'aeiou'.includes(char.toLowerCase())
}

