      `  async ${resource}FindMany(options?: RequestOptions): Promise<${name}[]> {`,
      `    return this.#request<${name}[]>('/${resource}', options)`,
      '  }',
    )
    lines.push('')
    lines.push(
      `  /** Retrieve a single ${name} by its unique identifier. */`,
      `  async ${resource}FindUnique(where: ${name}WhereUniqueInput, options?: RequestOptions): Promise<${name}> {`,
      `    return this.#request<${name}>(\`/${resource}/\${where.${idField.name}}\`, options)`,
      '  }',
    )
    lines.push('')
    lines.push(
      `  /** Create a new ${name} record. */`,
      `  async ${resource}Create(data: ${name}CreateInput, options?: RequestOptions): Promise<${name}> {`,
      `    return this.#request<${name}>('/${resource}', { method: 'POST', body: JSON.stringify(data), ...options })`,
      '  }',
    )
    lines.push('')
    lines.push(
      `  /** Update an existing ${name} record. */`,
      `  async ${resource}Update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput, options?: RequestOptions): Promise<${name}> {`,
      `    return this.#request<${name}>(\`/${resource}/\${where.${idField.name}}\`, { method: 'PATCH', body: JSON.stringify(data), ...options })`,
      '  }',
    )
    lines.push('')
    lines.push(
      `  /** Delete a ${name} record. */`,
      `  async ${resource}Delete(where: ${name}WhereUniqueInput, options?: RequestOptions): Promise<${name}> {`,
      `    return this.#request<${name}>(\`/${resource}/\${where.${idField.name}}\`, { method: 'DELETE', ...options })`,
      '  }',
    )
  }

  lines.push('}')
  return lines.join('\n')
}

/** Filters model fields to only scalar and enum kinds (skips relations). */
function scalarAndEnumFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
}

function camelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

/**
 * Naive English pluralizer. Covers the most common cases found in Prisma model names
 * without pulling in a runtime dependency.
 */
function pluralize(word: string): string {
  if (word.endsWith('s') || word.endsWith('x') || word.endsWith('z') || word.endsWith('sh') || word.endsWith('ch')) {
    return word + 'es'
  }
  if (word.endsWith('y') && !isVowel(word.charAt(word.length - 2))) {
    return word.slice(0, -1) + 'ies'
  }
  return word + 's'
}

function isVowel(char: string): boolean {
  return 'aeiou'.includes(char.toLowerCase())
}

