import { describe, expect, test } from 'vitest'

import { fieldToCreateInputType, fieldToTsType, mapScalarType } from '../type-mapper'

function makeField(overrides: Record<string, unknown> = {}) {
  return {
    kind: 'scalar' as const,
    name: 'field',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: 'String',
    hasDefaultValue: false,
    ...overrides,
  }
}

describe('mapScalarType', () => {
  test('maps String to string', () => {
    expect(mapScalarType('String')).toBe('string')
  })

  test('maps Int to number', () => {
    expect(mapScalarType('Int')).toBe('number')
  })

  test('maps Float to number', () => {
    expect(mapScalarType('Float')).toBe('number')
  })

  test('maps Boolean to boolean', () => {
    expect(mapScalarType('Boolean')).toBe('boolean')
  })

  test('maps DateTime to string', () => {
    expect(mapScalarType('DateTime')).toBe('string')
  })

  test('maps BigInt to bigint', () => {
    expect(mapScalarType('BigInt')).toBe('bigint')
  })

  test('maps Json to unknown', () => {
    expect(mapScalarType('Json')).toBe('unknown')
  })

  test('maps unknown type to unknown', () => {
    expect(mapScalarType('SomethingElse')).toBe('unknown')
  })
})

describe('fieldToTsType', () => {
  test('required scalar field', () => {
    expect(fieldToTsType(makeField())).toBe('string')
  })

  test('optional scalar field', () => {
    expect(fieldToTsType(makeField({ isRequired: false }))).toBe('string | null')
  })

  test('list field', () => {
    expect(fieldToTsType(makeField({ isList: true }))).toBe('string[]')
  })

  test('optional list field stays array (no null)', () => {
    expect(fieldToTsType(makeField({ isList: true, isRequired: false }))).toBe('string[]')
  })

  test('enum field uses type name', () => {
    expect(fieldToTsType(makeField({ kind: 'enum', type: 'Role' }))).toBe('Role')
  })

  test('object (relation) field uses type name', () => {
    expect(fieldToTsType(makeField({ kind: 'object', type: 'User' }))).toBe('User')
  })
})

describe('fieldToCreateInputType', () => {
  test('required field without default is not optional', () => {
    const result = fieldToCreateInputType(makeField())
    expect(result.optional).toBe(false)
  })

  test('field with default value is optional', () => {
    const result = fieldToCreateInputType(makeField({ hasDefaultValue: true }))
    expect(result.optional).toBe(true)
  })

  test('optional field is optional', () => {
    const result = fieldToCreateInputType(makeField({ isRequired: false }))
    expect(result.optional).toBe(true)
  })

  test('auto-generated field is optional', () => {
    const result = fieldToCreateInputType(makeField({ isGenerated: true }))
    expect(result.optional).toBe(true)
  })

  test('updatedAt field is optional', () => {
    const result = fieldToCreateInputType(makeField({ isUpdatedAt: true }))
    expect(result.optional).toBe(true)
  })
})

