import { describe, expect, test } from 'vitest'

import { generateRestClient } from '../code-generator'

function makeDmmf(models: any[] = [], enums: any[] []) {
  return {
    datamodel: {
      models,
      enums,
      types: [],
      indexes: [],
    },
    schema: {
      inputObjectTypes: {},
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  } as any
}

const userModel = {
  name: 'User',
  dbName: null,
  schema: null,
  fields: [
    {
      kind: 'scalar',
      name: 'id',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: true,
      isReadOnly: false,
      type: 'Int',
      hasDefaultValue: true,
      default: { name: 'autoincrement', args: [] },
    },
    {
      kind: 'scalar',
      name: 'email',
      isRequired: true,
      isList: false,
      isUnique: true,
      isId: false,
      isReadOnly: false,
      type: 'String',
      hasDefaultValue: false,
    },
    {
      kind: 'scalar',
      name: 'name',
      isRequired: false,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'String',
      hasDefaultValue: false,
    },
    {
      kind: 'object',
      name: 'posts',
      isRequired: false,
      isList: true,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'Post',
      hasDefaultValue: false,
      relationName: 'UserPosts',
    },
  ],
  uniqueFields: [],
  uniqueIndexes: [],
  primaryKey: null,
}

const postModel = {
  name: 'Post',
  dbName: null,
  schema: null,
  fields: [
    {
      kind: 'scalar',
      name: 'id',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: true,
      isReadOnly: false,
      type: 'String',
      hasDefaultValue: true,
      default: { name: 'uuid', args: [] },
    },
    {
      kind: 'scalar',
      name: 'title',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'String',
      hasDefaultValue: false,
    },
    {
      kind: 'scalar',
      name: 'published',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'Boolean',
      hasDefaultValue: true,
      default: false,
    },
  ],
  uniqueFields: [],
  uniqueIndexes: [],
  primaryKey: null,
}

const roleEnum = {
  name: 'Role',
  values: [
    { name: 'ADMIN', dbName: null },
    { name: 'USER', dbName: null },
  ],
}

describe('generateRestClient', () => {
  test('generates header', () => {
    const result = generateRestClient(makeDmmf())
    expect(result).toContain('Generated by @prisma/client-generator-rest')
    expect(result).toContain('Do not edit this file manually')
  })

  test('generates enum', () => {
    const result = generateRestClient(makeDmmf([], [roleEnum]))
    expect(result).toContain('export enum Role {')
    expect(result).toContain("ADMIN = 'ADMIN'")
    expect(result).toContain("USER = 'USER'")
  })

  test('generates model interface with scalar fields only', () => {
    const result = generateRestClient(makeDmmf([userModel]))
    expect(result).toContain('export interface User {')
    expect(result).toContain('id: number')
    expect(result).toContain('email: string')
    expect(result).toContain('name: string | null')
    // Relations should NOT appear in the interface
    expect(result).not.toContain('posts:')
  })

  test('generates create input with optional defaults', () => {
    const result = generateRestClient(makeDmmf([userModel]))
    expect(result).toContain('export interface UserCreateInput {')
    // id has a default so it should be optional
    expect(result).toContain('id?: number')
    // email is required with no default
    expect(result).toContain('email: string')
    // name is optional (not required)
    expect(result).toContain('name?: string | null')
  })

  test('generates update input with all optional fields', () => {
    const result = generateRestClient(makeDmmf([userModel]))
    expect(result).toContain('export interface UserUpdateInput {')
    expect(result).toContain('id?: number')
    expect(result).toContain('email?: string')
    expect(result).toContain('name?: string | null')
  })

  test('generates where unique input from id field', () => {
    const result = generateRestClient(makeDmmf([userModel]))
    expect(result).toContain('export interface UserWhereUniqueInput {')
    expect(result).toContain('id: number')
  })

  test('generates client class with CRUD methods', () => {
    const result = generateRestClient(makeDmmf([userModel]))
    expect(result).toContain('export class RestApiClient {')
    expect(result).toContain('usersFindMany')
    expect(result).toContain('usersFindUnique')
    expect(result).toContain('usersCreate')
    expect(result).toContain('usersUpdate')
    expect(result).toContain('usersDelete')
  })

  test('generates correct HTTP methods', () => {
    const result = generateRestClient(makeDmmf([postModel]))
    expect(result).toContain("method: 'POST'")
    expect(result).toContain("method: 'PATCH'")
    expect(result).toContain("method: 'DELETE'")
  })

  test('handles multiple models', () => {
    const result = generateRestClient(makeDmmf([userModel, postModel]))
    expect(result).toContain('export interface User {')
    expect(result).toContain('export interface Post {')
    expect(result).toContain('usersFindMany')
    expect(result).toContain('postsFindMany')
  })

  test('uses correct id type in where unique', () => {
    const result = generateRestClient(makeDmmf([postModel]))
    expect(result).toContain('export interface PostWhereUniqueInput {')
    expect(result).toContain('id: string')
  })

  test('findMany returns array', () => {
    const result = generateRestClient(makeDmmf([userModel]))
    expect(result).toContain('Promise<User[]>')
  })

  test('findUnique returns single model', () => {
    const result = generateRestClient(makeDmmf([userModel]))
    expect(result).toMatch(/usersFindUnique.*Promise<User>/)
  })
})

import * as fs from 'node:fs'
import * as path from 'node:path'

import Debug from '@prisma/debug'
import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './code-generator'

const debug = Debug('prisma:client-generator-rest')

const DEFAULT_OUTPUT = 'rest-client'

/**
 * Prisma generator that produces a typed REST API client.
 *
 * For each model in the schema, the generated client contains:
 * - A TypeScript interface matching the model's scalar fields
 * - Create/Update input interfaces
 * - CRUD methods (findMany, findUnique, create, update, delete) with proper types
 */
export class PrismaRestApiGenerator {
  getManifest(_config: GeneratorConfig): GeneratorManifest {
    return {
      defaultOutput: DEFAULT_OUTPUT,
      prettyName: 'Prisma REST API Client',
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = options.generator.output?.value
    if (!outputDir) {
      throw new Error('@prisma/client-generator-rest: No output directory specified.')
    }

    debug('Generating REST API client to %s', outputDir)

    const code = generateRestClient(options.dmmf)
    const outputFile = path.join(outputDir, 'index.ts')

    await fs.promises.mkdir(outputDir, { recursive: true })
    await fs.promises.writeFile(outputFile, code, 'utf-8')

    debug('REST API client generated successfully')
  }
}

